export const PROVIDER_PIXEL_LOGO_BUILD = Object.freeze({
  "width": 64,
  "height": 64,
  "encoding": "rgba-rle-v1",
  "monochromeColor": "#FFFFFF",
  "sourceVersion": "@lobehub/icons-static-svg@1.91.0"
});

export function decodeProviderPixelLogo(provider) {
  const logo = PROVIDER_PIXEL_LOGOS[provider];
  if (!logo) return null;
  const encoded = base64Bytes(logo.rgbaRleBase64);
  const rgba = new Uint8ClampedArray(logo.width * logo.height * 4);
  let input = 0;
  let output = 0;
  while (input < encoded.length) {
    const run = encoded[input] | (encoded[input + 1] << 8);
    for (let count = 0; count < run; count += 1) {
      rgba.set(encoded.subarray(input + 2, input + 6), output);
      output += 4;
    }
    input += 6;
  }
  if (output !== rgba.length) throw new Error("Invalid provider logo data: " + provider);
  return { width: logo.width, height: logo.height, rgba };
}

function base64Bytes(value) {
  if (typeof globalThis.atob === "function") {
    const binary = globalThis.atob(value);
    return Uint8Array.from(binary, (character) => character.charCodeAt(0));
  }
  return Uint8Array.from(globalThis.Buffer.from(value, "base64"));
}
